# imports
import torch


# pytorch model train function
def train(model, loader, criterion, optimizer, epochs=5):
    for epoch in epochs:
        for (x, y) in loader:
            optimizer.zero_grad()  
            pred = model.forward(x)
            loss = criterion(pred, y)
            loss.backward()
            optimizer.step()
    return model 


# call stack
def main():
    pass

if __name__ == "__main__":
    main()
    








